changeSet.sql:
ALTER TABLE nexus.retention_markers ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.retention_markers FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.retention_markers
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.retention_markers;
ALTER TABLE nexus.retention_markers NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.retention_markers DISABLE ROW LEVEL SECURITY;
